//! # PCAR wire codec — scaffold per F-mesh-5 third-tier speedup.
//!
//! Encode/decode round-trip is correct; production blocked by F-mesh-3-class
//! fidelity falsification under zero-fill (parity gap, not codec bug).
//!
//! When the upstream fidelity issue is resolved, swap fat-station-flow's body
//! kind to PCAR for split-b (the heavy 21504-float intermediate).
//!
//! ## Wire format
//!
//! A PCAR body is a single contiguous block:
//!
//! ```text
//! [0..3]   tag           u8[4]  ASCII 'P','C','A','R'
//! [4..7]   layer_index   u32 LE
//! [8..11]  k_components  u32 LE  (the actual rank used at this layer)
//! [12..15] hidden_dim    u32 LE  (sender's d, for receiver sanity check)
//! [16..]   components    f32 LE × k_components
//! ```
//!
//! Total fixed overhead: [`PCAR_HEADER_BYTES`] = 16 bytes. The 24-byte
//! `methodology` + `basis_fp` extension proposed in
//! `AETHER_FLOW_INTEGRATION_SCOPE.md` §4 is intentionally NOT in this
//! scaffold — adding those fields requires the methodology registry that
//! Phase B of the scope doc names as a separate cross-codebase artifact. The
//! 16-byte form is the minimum that round-trips a PCA-projected residual
//! across a matching basis on both ends.
//!
//! ## Math
//!
//! Encoding (against a per-layer basis loaded from a `.pca` sidecar):
//!
//! ```text
//! centered  = residual - mean
//! c_i       = basis[i] · centered    for i in 0..k
//! ```
//!
//! Decoding:
//!
//! ```text
//! residual ≈ mean + Σ c_i · basis[i]
//! ```
//!
//! `basis` is row-major `k × d` (one principal component per row, each row a
//! unit vector under the calibration corpus). `mean` is length d. Both come
//! from [`crate::rknot::manifest_from_pca::PcaBasis::layer`].
//!
//! Reconstruction is rank-truncated, so cosine ≥ 0.95 is the round-trip pass
//! bar — bit-exact recovery is impossible by construction (that is the whole
//! point of compressing `d` floats down to `k`).
//!
//! ## Bytes saved per hop
//!
//! At gemma4-31b's `hidden_dim = 5376`:
//!
//! | k    | bytes on wire (16 + 4k) | bytes saved | wire reduction |
//! |-----:|------------------------:|------------:|---------------:|
//! |    8 |                      48 |      21 456 |          448× |
//! |   64 |                     272 |      21 232 |           79× |
//! |  192 |                     784 |      20 720 |           27× |
//!
//! See [`bytes_saved`] for the exact accounting.
//!
//! ## Status
//!
//! This is foundation only. Per the user's wave-7 directive, the codec is
//! NOT wired into `fat-station-flow.rs` here. The body-kind discriminator
//! question (scope §7: route-opcode vs handshake-version vs JSON-meta byte)
//! must be resolved before this codec ships on the wire. Until F-mesh-3
//! parity closes, any PCAR transit measurement is measurement of a broken
//! model's broken output.

use crate::rknot::manifest_from_pca::PcaBasis;

/// 4-byte ASCII tag for the PCAR body format.
pub const PCAR_TAG: [u8; 4] = *b"PCAR";

/// Fixed wire overhead in bytes: tag (4) + layer (4) + k (4) + hidden_dim (4).
pub const PCAR_HEADER_BYTES: usize = 16;

/// Bytes saved per hop when shipping PCAR instead of a raw f32 residual.
///
/// `bytes_saved(d, k) = d * 4 - (PCAR_HEADER_BYTES + k * 4)`
///
/// Returns 0 if the PCAR encoding would be the same size or larger than the
/// raw residual (i.e. for very small `d` or very large `k`).
#[inline]
pub fn bytes_saved(hidden_dim: usize, k: usize) -> usize {
    let raw = hidden_dim.saturating_mul(4);
    let pcar = PCAR_HEADER_BYTES.saturating_add(k.saturating_mul(4));
    raw.saturating_sub(pcar)
}

/// Encode a residual into the PCAR wire body.
///
/// Projects `residual` (length `pca_basis.hidden_dim`) into the per-layer
/// principal-component basis and packs the result with a [`PCAR_HEADER_BYTES`]
/// prefix.
///
/// Returns the byte buffer ready to ship as the body of a fat-station-flow
/// frame. Use [`decode_residual`] on the receiver with the same `pca_basis`
/// (matching `basis_fp`, in the production design — the scaffold trusts the
/// caller).
///
/// # Panics
///
/// Panics if `pca_basis` has no fitted basis at `layer` (i.e.
/// [`PcaBasis::layer`] returns `None`) or if `residual.len() !=
/// pca_basis.hidden_dim`. Panics rather than `Result` keep the scaffold
/// surface narrow; production wiring (when fat-station-flow gates a body
/// kind on this) should adapt to the existing error-vent path.
pub fn encode_residual(residual: &[f32], pca_basis: &PcaBasis, layer: u32) -> Vec<u8> {
    let layer_idx = layer as usize;
    let d = pca_basis.hidden_dim;
    assert_eq!(
        residual.len(),
        d,
        "encode_residual: residual length {} != hidden_dim {}",
        residual.len(),
        d
    );

    let (k, mean, basis) = pca_basis.layer(layer_idx).unwrap_or_else(|| {
        panic!(
            "encode_residual: no PCA basis fitted for layer {}",
            layer_idx
        )
    });

    debug_assert_eq!(mean.len(), d);
    debug_assert_eq!(basis.len(), k * d);

    // Project: c_i = basis[i] · (residual - mean), for i in 0..k.
    let mut components = vec![0.0f32; k];
    for i in 0..k {
        let row = &basis[i * d..(i + 1) * d];
        let mut acc = 0.0f32;
        for j in 0..d {
            acc += row[j] * (residual[j] - mean[j]);
        }
        components[i] = acc;
    }

    let mut out = Vec::with_capacity(PCAR_HEADER_BYTES + k * 4);
    out.extend_from_slice(&PCAR_TAG);
    out.extend_from_slice(&layer.to_le_bytes());
    out.extend_from_slice(&(k as u32).to_le_bytes());
    out.extend_from_slice(&(d as u32).to_le_bytes());
    for &c in &components {
        out.extend_from_slice(&c.to_le_bytes());
    }
    out
}

/// Decode a PCAR wire body and reconstruct the residual via the inverse PCA
/// basis lift `mean + Σ c_i · basis[i]`.
///
/// Validates the [`PCAR_TAG`] magic, the encoded `hidden_dim` against the
/// caller-supplied `hidden_dim`, the `k_components` against the basis loaded
/// for that layer, and the payload length against the header's claim. Any
/// mismatch returns `Err`; the scaffold does NOT silently fall back. The
/// production code path is expected to map these errors to the
/// `application/x-aeon-flow` 412 vent (scope §4).
pub fn decode_residual(
    payload: &[u8],
    pca_basis: &PcaBasis,
    hidden_dim: usize,
) -> Result<Vec<f32>, String> {
    if payload.len() < PCAR_HEADER_BYTES {
        return Err(format!(
            "decode_residual: payload {} bytes < header {}",
            payload.len(),
            PCAR_HEADER_BYTES
        ));
    }
    if payload[..4] != PCAR_TAG {
        return Err(format!(
            "decode_residual: bad tag {:?}, expected PCAR",
            &payload[..4]
        ));
    }

    let layer_le: [u8; 4] = payload[4..8].try_into().unwrap();
    let k_le: [u8; 4] = payload[8..12].try_into().unwrap();
    let d_le: [u8; 4] = payload[12..16].try_into().unwrap();
    let layer = u32::from_le_bytes(layer_le) as usize;
    let k = u32::from_le_bytes(k_le) as usize;
    let d_wire = u32::from_le_bytes(d_le) as usize;

    if d_wire != hidden_dim {
        return Err(format!(
            "decode_residual: hidden_dim mismatch wire={} expected={}",
            d_wire, hidden_dim
        ));
    }
    if d_wire != pca_basis.hidden_dim {
        return Err(format!(
            "decode_residual: hidden_dim mismatch wire={} basis={}",
            d_wire, pca_basis.hidden_dim
        ));
    }

    let body_bytes = payload.len() - PCAR_HEADER_BYTES;
    if body_bytes != k * 4 {
        return Err(format!(
            "decode_residual: body {} bytes != k({}) * 4 = {}",
            body_bytes,
            k,
            k * 4
        ));
    }

    let (k_basis, mean, basis) = pca_basis
        .layer(layer)
        .ok_or_else(|| format!("decode_residual: no PCA basis for layer {}", layer))?;
    if k_basis != k {
        return Err(format!(
            "decode_residual: k mismatch wire={} basis={}",
            k, k_basis
        ));
    }
    debug_assert_eq!(mean.len(), hidden_dim);
    debug_assert_eq!(basis.len(), k * hidden_dim);

    // Parse the k components.
    let mut components = vec![0.0f32; k];
    for i in 0..k {
        let off = PCAR_HEADER_BYTES + i * 4;
        let bytes: [u8; 4] = payload[off..off + 4].try_into().unwrap();
        components[i] = f32::from_le_bytes(bytes);
    }

    // Lift: residual = mean + Σ c_i · basis[i]
    let mut residual = mean.to_vec();
    for i in 0..k {
        let c = components[i];
        let row = &basis[i * hidden_dim..(i + 1) * hidden_dim];
        for j in 0..hidden_dim {
            residual[j] += c * row[j];
        }
    }
    Ok(residual)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::rknot::manifest_from_pca::PcaBasis;
    use crate::standing_wave_pinning::{fit_pca, write_pca_bases};

    /// Build a `PcaBasis` in memory by fitting on synthetic samples and
    /// round-tripping through the on-disk PCAB sidecar (the only public
    /// constructor). Returns the basis plus the calibration samples used
    /// (so the round-trip test can ride on a held-out activation drawn from
    /// the same distribution).
    fn synth_basis(d: usize, k: usize, num_layers: usize) -> (PcaBasis, Vec<Vec<f32>>) {
        // 64 samples on a low-rank-ish manifold: a few latent factors plus
        // small isotropic noise. PCA of dimension k=8 should explain most of
        // the variance, hence cosine-of-reconstruction ≥ 0.95 is reachable.
        let n = 64;
        let mut rng = fastrand::Rng::with_seed(0x5EED);
        // Latent factor count: keep below k so PCA can recover the manifold.
        let latent = (k / 2).max(2).min(d);
        let mut factors = vec![0.0f32; latent * d];
        for v in factors.iter_mut() {
            *v = rng.f32() - 0.5;
        }
        let mut samples = Vec::with_capacity(n);
        for _ in 0..n {
            let mut s = vec![0.0f32; d];
            for f in 0..latent {
                let coeff = rng.f32() - 0.5;
                let row = &factors[f * d..(f + 1) * d];
                for j in 0..d {
                    s[j] += coeff * row[j];
                }
            }
            // Small noise so PCA doesn't trivially hit cosine=1.
            for j in 0..d {
                s[j] += 0.01 * (rng.f32() - 0.5);
            }
            samples.push(s);
        }
        let (mean, basis) = fit_pca(&samples, k, 16, 0xC0DE);

        // The PcaBasis on-disk format expects (layer_idx, k, mean, basis)
        // tuples. Replicate the fitted basis at every layer so any
        // layer-index test works.
        let mut bases = Vec::with_capacity(num_layers);
        for l in 0..num_layers {
            bases.push((l, k, mean.clone(), basis.clone()));
        }
        // Unique per-call path: PID isolates across test runs, the static
        // counter isolates across the parallel-running tests in this module.
        use std::sync::atomic::{AtomicU64, Ordering};
        static SERIAL: AtomicU64 = AtomicU64::new(0);
        let serial = SERIAL.fetch_add(1, Ordering::Relaxed);
        let tmp = std::env::temp_dir().join(format!(
            "pcar_codec_test_{}_{}_{}_{}.pca",
            d,
            k,
            std::process::id(),
            serial
        ));
        let path = tmp.to_string_lossy().to_string();
        write_pca_bases(&path, d, num_layers, &bases).expect("write_pca_bases");
        let basis = PcaBasis::open(&path).expect("PcaBasis::open");
        let _ = std::fs::remove_file(&path);
        (basis, samples)
    }

    fn cosine(a: &[f32], b: &[f32]) -> f32 {
        let mut dot = 0.0f64;
        let mut na = 0.0f64;
        let mut nb = 0.0f64;
        for (x, y) in a.iter().zip(b.iter()) {
            dot += (*x as f64) * (*y as f64);
            na += (*x as f64) * (*x as f64);
            nb += (*y as f64) * (*y as f64);
        }
        let denom = (na.sqrt() * nb.sqrt()).max(1e-30);
        (dot / denom) as f32
    }

    #[test]
    fn round_trip_cosine_at_least_0_95() {
        let d = 256;
        let k = 16;
        let (basis, samples) = synth_basis(d, k, 4);

        // Use the first sample as the residual under test. It lies on the
        // calibration manifold, so a rank-k projection should recover it
        // with cosine ≥ 0.95.
        let residual = &samples[0];
        let body = encode_residual(residual, &basis, 0);

        // Header check baked into the round-trip.
        assert_eq!(body.len(), PCAR_HEADER_BYTES + k * 4);

        let recovered = decode_residual(&body, &basis, d).expect("decode");
        let c = cosine(residual, &recovered);
        // Visible under `cargo test -- --nocapture` for the operational
        // metric the scaffold doc records.
        println!(
            "PCAR round-trip cosine = {:.6} (d={}, k={}, body={} B raw={} B saved={} B)",
            c,
            d,
            k,
            body.len(),
            d * 4,
            bytes_saved(d, k)
        );
        assert!(
            c >= 0.95,
            "round-trip cosine {} below 0.95 pass bar (k={}, d={})",
            c,
            k,
            d
        );
    }

    #[test]
    fn header_fields_parse_correctly() {
        let d = 64;
        let k = 4;
        let (basis, samples) = synth_basis(d, k, 8);
        let layer = 5u32;

        let body = encode_residual(&samples[0], &basis, layer);

        // Tag.
        assert_eq!(&body[0..4], &PCAR_TAG);
        // Layer index, little-endian.
        let layer_decoded = u32::from_le_bytes(body[4..8].try_into().unwrap());
        assert_eq!(layer_decoded, layer);
        // k_components.
        let k_decoded = u32::from_le_bytes(body[8..12].try_into().unwrap());
        assert_eq!(k_decoded as usize, k);
        // hidden_dim.
        let d_decoded = u32::from_le_bytes(body[12..16].try_into().unwrap());
        assert_eq!(d_decoded as usize, d);
        // Payload length matches header claim.
        assert_eq!(body.len() - PCAR_HEADER_BYTES, k * 4);

        // Decode round-trip on the same body, just to confirm the parser
        // agrees with the writer.
        let recovered = decode_residual(&body, &basis, d).expect("decode");
        assert_eq!(recovered.len(), d);
    }

    #[test]
    fn bytes_saved_at_gemma4_dim() {
        // gemma4-31b hidden_dim = 5376. At k = 64 the wire body is
        // 16 + 256 = 272 bytes vs 21504 raw bytes, so 21232 bytes saved.
        assert_eq!(bytes_saved(5376, 64), 21504 - 272);
        assert_eq!(bytes_saved(5376, 64), 21232);

        // Sanity: at k = 8 the savings are even larger.
        assert_eq!(bytes_saved(5376, 8), 21504 - (16 + 32));
        // Sanity: at k = hidden_dim the wire only loses to the 16-byte header.
        assert_eq!(bytes_saved(5376, 5376), 0);
        // And once k * 4 + 16 > raw, savings clamp at 0 instead of underflowing.
        assert_eq!(bytes_saved(64, 1024), 0);
    }

    #[test]
    fn decode_rejects_bad_tag() {
        let d = 64;
        let k = 4;
        let (basis, samples) = synth_basis(d, k, 1);
        let mut body = encode_residual(&samples[0], &basis, 0);
        body[0] = b'X';
        let err = decode_residual(&body, &basis, d).unwrap_err();
        assert!(
            err.contains("bad tag"),
            "expected bad-tag error, got: {}",
            err
        );
    }

    #[test]
    fn decode_rejects_hidden_dim_mismatch() {
        let d = 64;
        let k = 4;
        let (basis, samples) = synth_basis(d, k, 1);
        let body = encode_residual(&samples[0], &basis, 0);
        let err = decode_residual(&body, &basis, d + 1).unwrap_err();
        assert!(
            err.contains("hidden_dim mismatch"),
            "expected hidden_dim mismatch, got: {}",
            err
        );
    }
}
